from collections import Counter

def get_score(dice):
    # Count occurrences of each die value
    counts = Counter(dice)

    # Check for "Straight"
    if sorted(counts.keys()) == [1, 2, 3, 4, 5, 6]:
        return 1000

    # Check for "Three pairs"
    if len(counts) == 3 and all(count == 2 for count in counts.values()):
        return 750

    score = 0

    # Check for "Three of a kind" and higher
    for num in range(1, 7):
        if counts[num] >= 3:
            if num == 1:
                score += 1000 * (counts[num] // 3)
            else:
                score += 100 * num * (counts[num] // 3)
            counts[num] %= 3

    # Check for "Four of a kind", "Five of a kind", "Six of a kind"
    for num in range(1, 7):
        if counts[num] == 4:
            score += 2 * (1000 if num == 1 else 100 * num)
        elif counts[num] == 5:
            score += 3 * (1000 if num == 1 else 100 * num)
        elif counts[num] == 6:
            score += 4 * (1000 if num == 1 else 100 * num)

    # Add points for individual 1s and 5s
    score += counts[1] * 100
    score += counts[5] * 50

    return score if score > 0 else "Zonk"

