def solve(st):
    def generate_possibilities(st):
        possibilities = ['']
        for char in st:
            new_possibilities = []
            if char == 'a':
                for p in possibilities:
                    new_possibilities.append(p + 'b')
            elif char == 'z':
                for p in possibilities:
                    new_possibilities.append(p + 'y')
            else:
                for p in possibilities:
                    new_possibilities.append(p + chr(ord(char) - 1))
                    new_possibilities.append(p + chr(ord(char) + 1))
            possibilities = new_possibilities
        return possibilities

    def is_palindrome(s):
        return s == s[::-1]

    possibilities = generate_possibilities(st)
    for possibility in possibilities:
        if is_palindrome(possibility):
            return True
    return False

