def format_number(n):
    if n == 0:
        return ""

    n_str = str(n)
    length = len(n_str)
    components = []

    for i, digit in enumerate(n_str):
        if digit != '0':
            power = length - i - 1
            if power == 0:
                components.append(f"{digit}")
            else:
                components.append(f"{digit}*{'1' + '0' * power}")

    return '+'.join(components)

