def transform_string(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    exceptions = {'c', 'o', 'd', 'e'}
    result = []

    for char in s:
        if char in exceptions:
            if char == 'c':
                new_char = chr(ord(char) - 1)
            elif char == 'o':
                new_char = chr(ord(char) - 1)
            elif char == 'd':
                new_char = chr(ord(char) - 3)
            elif char == 'e':
                new_char = chr(ord(char) - 4)
            if new_char in exceptions:
                new_char = char
            result.append(new_char)
        elif char in vowels:
            new_char = chr(ord(char) - 5)
            if new_char < 'a':
                new_char = chr(ord(new_char) + 26)
            result.append(new_char)
        else:
            new_char = chr(ord(char) + 9)
            if new_char > 'z':
                new_char = chr(ord(new_char) - 26)
            result.append(new_char)

    return ''.join(result)

