def replace_yellow_with_green(color):
    # Dictionary mapping yellow HTML color names to green shades
    yellow_to_green = {
        "gold": "ForestGreen",
        "khaki": "LimeGreen",
        "lemonchiffon": "PaleGreen",
        "lightgoldenrodyellow": "SpringGreen",
        "lightyellow": "MintCream",
        "palegoldenrod": "LightGreen",
        "yellow": "Lime"
    }

    # Check if the input is an HTML color name
    if not color.startswith("#"):
        color_lower = color.lower()
        if color_lower in yellow_to_green:
            return yellow_to_green[color_lower]
        else:
            return color

    # If the input is a hex color code
    else:
        # Extract R, G, B values
        r = int(color[1:3], 16)
        g = int(color[3:5], 16)
        b = int(color[5:7], 16)

        # Check if the color is "yellow"
        if r > b and g > b:
            # Rearrange the values
            values = sorted([r, g, b])
            new_r, new_g, new_b = values[0], values[2], values[1]
            # Format the new hex code
            new_color = f"#{new_r:02X}{new_g:02X}{new_b:02X}"
            # Return in the same case as input
            if color.islower():
                return new_color.lower()
            else:
                return new_color.upper()
        else:
            return color

