def can_be_increasing(sequence):
    removals = 0
    for i in range(len(sequence) - 1):
        if sequence[i] >= sequence[i + 1]:
            removals += 1
            if removals > 1:
                return False
            if i > 0 and sequence[i - 1] >= sequence[i + 1]:
                if i + 2 < len(sequence) and sequence[i] >= sequence[i + 2]:
                    return False
    return True

