def is_prime(num):
    if num <= 1:
        return False
    if num == 2:
        return True
    if num % 2 == 0:
        return False
    for i in range(3, int(num**0.5) + 1, 2):
        if num % i == 0:
            return False
    return True

def is_mersenne_prime(n):
    if n < 2:
        return False
    mersenne_number = (1 << n) - 1  # 2^n - 1
    return is_prime(mersenne_number)

