def next_smaller(n):
    digits = list(str(n))
    length = len(digits)

    # Step 2: Traverse the list from right to left
    for i in range(length - 2, -1, -1):
        if digits[i] > digits[i + 1]:
            # Step 4: Find the largest digit to the right of i that is smaller than digits[i]
            max_j = i + 1
            for j in range(i + 1, length):
                if digits[j] < digits[i] and digits[j] > digits[max_j]:
                    max_j = j
            # Step 5: Swap these two digits
            digits[i], digits[max_j] = digits[max_j], digits[i]
            # Step 6: Reverse the sequence of digits to the right of i
            digits = digits[:i + 1] + sorted(digits[i + 1:], reverse=True)
            # Step 8: Check for leading zero
            if digits[0] == '0':
                return -1
            # Step 9: Return the resulting number
            return int(''.join(digits))
    return -1

