def next_bigger_number(n):
    digits = list(str(n))
    length = len(digits)

    # Step 2: Find the first pair of digits from the right where the left is smaller than the right
    for i in range(length - 2, -1, -1):
        if digits[i] < digits[i + 1]:
            break
    else:
        # If no such pair is found, return -1
        return -1

    # Step 4: Find the smallest digit on the right of the found pair that is larger than digits[i]
    for j in range(length - 1, i, -1):
        if digits[j] > digits[i]:
            break

    # Step 5: Swap these two digits
    digits[i], digits[j] = digits[j], digits[i]

    # Step 6: Reverse the sequence of digits to the right of the original position
    digits = digits[:i + 1] + digits[i + 1:][::-1]

    # Step 7: Convert the list of digits back to an integer and return it
    return int(''.join(digits))

