def count_paths(n, m, grid):
    MOD = 10**9 + 7

    # Initialize dp array
    dp = [[0] * m for _ in range(n)]
    dp[0][0] = 1  # Start at the top-left corner

    # Precompute the number of rocks in each row and column up to each cell
    row_rocks = [[0] * m for _ in range(n)]
    col_rocks = [[0] * m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if grid[i][j] == 'R':
                row_rocks[i][j] = 1
                col_rocks[i][j] = 1
            if j > 0:
                row_rocks[i][j] += row_rocks[i][j - 1]
            if i > 0:
                col_rocks[i][j] += col_rocks[i - 1][j]

    # Fill the dp table
    for i in range(n):
        for j in range(m):
            if i == 0 and j == 0:
                continue
            if grid[i][j] == 'R':
                continue

            # Calculate ways from the left
            if j > 0:
                if row_rocks[i][j - 1] == row_rocks[i][j]:
                    dp[i][j] = (dp[i][j] + dp[i][j - 1]) % MOD

            # Calculate ways from above
            if i > 0:
                if col_rocks[i - 1][j] == col_rocks[i][j]:
                    dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD

    return dp[n - 1][m - 1]

