def differentiate(polynomial, x_value):
    # Parse the polynomial and differentiate
    terms = polynomial.replace('-', '+-').split('+')
    derivative_terms = []

    for term in terms:
        term = term.strip()
        if 'x' in term:
            if '^' in term:
                coeff, exp = term.split('x^')
                coeff = int(coeff) if coeff not in ('', '+', '-') else (1 if coeff in ('', '+') else -1)
                exp = int(exp)
                if exp != 0:
                    new_coeff = coeff * exp
                    new_exp = exp - 1
                    if new_exp == 0:
                        derivative_terms.append(f"{new_coeff}")
                    elif new_exp == 1:
                        derivative_terms.append(f"{new_coeff}x")
                    else:
                        derivative_terms.append(f"{new_coeff}x^{new_exp}")
            else:
                coeff = term.replace('x', '')
                coeff = int(coeff) if coeff not in ('', '+', '-') else (1 if coeff in ('', '+') else -1)
                derivative_terms.append(f"{coeff}")
        else:
            # Constant term, derivative is 0, so we skip it
            continue

    # Evaluate the derivative at x_value
    result = 0
    for term in derivative_terms:
        if 'x' in term:
            if '^' in term:
                coeff, exp = term.split('x^')
                coeff = int(coeff)
                exp = int(exp)
                result += coeff * (x_value ** exp)
            else:
                coeff = term.replace('x', '')
                coeff = int(coeff)
                result += coeff * x_value
        else:
            result += int(term)

    return result

