from collections import deque

def solve_parking_lot(n, k, grid):
    moves = []
    move_limit = 20000

    # Helper function to find the empty space
    def find_empty_spaces():
        empty_spaces = []
        for r in range(4):
            for c in range(n):
                if grid[r][c] == 0:
                    empty_spaces.append((r, c))
        return empty_spaces

    # Helper function to check if a car can be moved to its designated parking space
    def can_park(car, r, c):
        if r == 0 and grid[0][c] == car:
            return True
        if r == 3 and grid[3][c] == car:
            return True
        return False

    # Helper function to move a car
    def move_car(car, from_r, from_c, to_r, to_c):
        grid[to_r][to_c] = car
        grid[from_r][from_c] = 0
        moves.append((car, to_r + 1, to_c + 1))

    # BFS to explore all possible states
    def bfs():
        queue = deque()
        empty_spaces = find_empty_spaces()
        queue.append((grid, empty_spaces, 0))
        visited = set()
        visited.add(tuple(map(tuple, grid)))

        while queue:
            current_grid, empty_spaces, move_count = queue.popleft()

            if move_count > move_limit:
                return -1

            # Try to move cars into their designated parking spaces
            for r in range(1, 3):
                for c in range(n):
                    car = current_grid[r][c]
                    if car != 0 and can_park(car, r, c):
                        if r == 1:
                            move_car(car, r, c, 0, c)
                        else:
                            move_car(car, r, c, 3, c)
                        return move_count + 1

            # Generate all possible moves
            for empty_r, empty_c in empty_spaces:
                for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    new_r, new_c = empty_r + dr, empty_c + dc
                    if 0 <= new_r < 4 and 0 <= new_c < n:
                        new_grid = [row[:] for row in current_grid]
                        new_grid[empty_r][empty_c], new_grid[new_r][new_c] = new_grid[new_r][new_c], new_grid[empty_r][empty_c]
                        new_state = tuple(map(tuple, new_grid))
                        if new_state not in visited:
                            visited.add(new_state)
                            new_empty_spaces = [(new_r, new_c) if (empty_r, empty_c) == (new_r, new_c) else (empty_r, empty_c) for empty_r, empty_c in empty_spaces]
                            queue.append((new_grid, new_empty_spaces, move_count + 1))

        return -1

    result = bfs()
    if result == -1:
        print(-1)
    else:
        print(len(moves))
        for move in moves:
            print(*move)

